class Solution:
    def encode(self, strs):
        return ''.join(f'{len(s)}#{s}' for s in strs)

    def decode(self, data):
        result = []
        i = 0
        while i < len(data):
            j = data.index('#', i)
            size = int(data[i:j])
            start = j + 1
            result.append(data[start:start + size])
            i = start + size
        return result

    def encodeDecode(self, strs):
        return self.decode(self.encode(strs))
